import React from 'react';
import { Line } from 'react-chartjs-2';

function Chart(props){
    const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul','Aug', 'Sep', 'Oct', 'Nov', 'Dec']
    const dates = props.tradeList.map(item => item.id)
    const months =props.tradeList.map(month => month.id)
    const profits = props.tradeList.map(trade => trade.profitLoss)
    console.log(months)

    return(
        <div className='chart'>
            <Line
                data={{
                    labels:monthNames,
                    datasets:[{
                        label:'Profit',
                        data:profits,
                        fill:false,
                        borderColor:'rgb(75, 192, 192)',
                        tension:0.1
                    }]
                }} />
        </div>
    )
}

export default Chart;
